fn visit_node<F>(id: NodeId, cb: &mut F) -> Option<NodeId>
where
    F: FnMut(NodeId) -> bool,
{
    if cb(id) {
        Some(id)
    } else {
        None
    }
}

fn visit_optional_node<F>(id: Option<NodeId>, cb: &mut F) -> Option<NodeId>
where
    F: FnMut(NodeId) -> bool,
{
    id.and_then(|id| visit_node(id, cb))
}

fn visit_nodes<L, F>(lookup: &L, id: NodeArrayId, cb: &mut F) -> Option<NodeId>
where
    L: NodeLookup,
    F: FnMut(NodeId) -> bool,
{
    for node in &lookup.node_array(id).nodes {
        if cb(*node) {
            return Some(*node);
        }
    }
    None
}

fn visit_optional_nodes<L, F>(lookup: &L, id: Option<NodeArrayId>, cb: &mut F) -> Option<NodeId>
where
    L: NodeLookup,
    F: FnMut(NodeId) -> bool,
{
    id.and_then(|id| visit_nodes(lookup, id, cb))
}
